sudo -u ec2-user bash -c 'cat > /tmp/kind.py <<PYEOF
import json, glob, os, collections
os.chdir("/home/ec2-user/platform/data/smoker-shard-a")
kinds = collections.Counter()
for p in sorted(glob.glob("*/cases/*.json")):
    d = json.load(open(p))
    t = d["trace"]
    if t["outcome"] != "failure":
        continue
    # Categorize
    if not t["steps"]:
        kinds["no_steps"] += 1
        continue
    s0 = t["steps"][0]
    obs0 = s0["observation"]
    rd = s0.get("resultDetail") or ""
    if "No accessibility tree" in obs0:
        kinds["empty_obs"] += 1
    elif "Bridge process terminated" in rd:
        kinds["bridge_crash"] += 1
    elif "Timeout" in rd:
        kinds["step1_timeout"] += 1
    elif t["totalSteps"] >= 5:
        kinds["genuine_failure"] += 1
    else:
        kinds["other_early"] += 1
for k, v in kinds.most_common():
    print(f"{k}: {v}")
PYEOF
python3.11 /tmp/kind.py'
